qry:select.qry:xquery:
	for $r in SQL('
SELECT
	L.oi_personal_emp

FROM
	ORG03_EMPRESAS as E, 
	PER02_PERSONAL_EMP as L,
	PER01_PERSONAL as P
	{%?($SOURCE/@CONVENIO!='') {% ,ORG18_CATEGORIAS %} {% %} %}
	{%?($SOURCE/@PUESTO  !='') {% ,ORG04_POSICIONES %} {% %} %}
	{%?($SOURCE/@PAIS_NAC!='' or $SOURCE/@PROVINCIA_NAC!='') {% ,(select PN.oi_pais, PN.oi_provincia, LN.oi_localidad from ORG35_PROVINCIAS as PN, ORG19_LOCALIDADES as LN join PN.oi_provincia inner LN.oi_provincia ) as LOC_NAC %} {% %} %}
	{%?($SOURCE/@PAIS_RES!='' or $SOURCE/@PROVINCIA_RES!='' or $SOURCE/@LOCALIDAD_RES!='') {% ,(select PN.oi_pais, PR.oi_provincia, LR.oi_localidad, PR.oi_personal from ORG35_PROVINCIAS as PR, ORG19_LOCALIDADES as LR,  PER01_DOMIC_PER as PR, join PN.oi_provincia inner LN.oi_provincia, PR.oi_localidad inner LOC.oi_localidad) as LOC_RES %} {% %} %}

JOIN
	E.oi_empresa INNER L.oi_empresa,
	L.oi_personal INNER P.oi_personal
	{%?($SOURCE/@CONVENIO!='') {% ,ORG18_CATEGORIAS.oi_categoria INNER L.oi_categoria_ult %} {% %} %}
	{%?($SOURCE/@PUESTO  !='') {% ,ORG04_POSICIONES.oi_posicion INNER L.oi_posicion_ult %} {% %} %}
	{%?($SOURCE/@PAIS_NAC!='' or $SOURCE/@PROVINCIA_NAC!='') {% ,LOC_NAC.oi_localidad INNER P.oi_local_nacim %} {% %} %}
	{%?($SOURCE/@PAIS_RES!='' or $SOURCE/@PROVINCIA_RES!='' or $SOURCE/@LOCALIDAD_RES!='') {% ,LOC_RES.oi_personal INNER P.oi_personal %} {% %} %}

WHERE
	1=1
	{%?($SOURCE/@EDAD_DESDE     ='') {% %} {% and P.f_nacim >= { datetime(string(string(Current-Date())-10000*$SOURCE/@EDAD_DESDE)) } %} %}
	{%?($SOURCE/@EDAD_HASTA     ='') {% %} {% and P.f_nacim <= { datetime(string(string(Current-Date())-10000*$SOURCE/@EDAD_HASTA)) } %} %}
	{%?($SOURCE/@SEXO           ='') {% %} {% and P.c_sexo = { $SOURCE/@SEXO } %} %}
	{%?($SOURCE/@GRUPO_SANGUINEO='') {% %} {% and P.oi_grupo_sanguineo = { $SOURCE/@GRUPO_SANGUINEO } %} %}
	{%?($SOURCE/@ESTADO_CIVIL   ='') {% %} {% and P.oi_estado_civil = { $SOURCE/@ESTADO_CIVIL } %} %}
	{%?($SOURCE/@EMPRESA        ='') {% %} {% and E.oi_empresa = { $SOURCE/@EMPRESA } %} %}
	{%?($SOURCE/@UBICACION      ='') {% %} {% and L.oi_ubicacion = { $SOURCE/@UBICACION } %} %}
	{%?($SOURCE/@FUNCION        ='') {% %} {% and L.oi_funcion = { $SOURCE/@FUNCION } %} %}
	{%?($SOURCE/@CALENDARIO     ='') {% %} {% and L.oi_calendario_ult = ({%=$SOURCE/@CALENDARIO %}) %} %}
	{%?($SOURCE/@INGRESO_DESDE  ='') {% %} {% and L.f_ingreso >= { datetime($SOURCE/@INGRESO_DESDE) } %} %}
	{%?($SOURCE/@INGRESO_HASTA  ='') {% %} {% and L.f_ingreso <= { datetime($SOURCE/@INGRESO_HASTA) } %} %}
	{%?($SOURCE/@IND_ACTIVO     ='') {% %} {% and L.oi_indic_activo = { $SOURCE/@IND_ACTIVO } %} %}
	{%?($SOURCE/@TIPO_PERSONAL  ='') {% %} {% and L.oi_tipo_personal = { $SOURCE/@TIPO_PERSONAL } %} %}
	{%?($SOURCE/@CENTRO_COSTO   ='') {% %} {% and L.oi_ctro_costo_ult = { $SOURCE/@CENTRO_COSTO } %} %}
	{%?($SOURCE/@OBRA_SOCIAL    ='') {% %} {% and L.oi_obra_social = { $SOURCE/@OBRA_SOCIAL } %} %}
	{%?($SOURCE/@FORMA_PAGO     ='') {% %} {% and L.oi_forma_pago = { $SOURCE/@FORMA_PAGO } %} %}
	{%?($SOURCE/@SINDICATO      ='') {% %} {% and L.oi_sindicato = { $SOURCE/@SINDICATO } %} %}
	{%?($SOURCE/@CATEGORIA      ='') {% %} {% and L.oi_categoria_ult = { $SOURCE/@CATEGORIA } %} %}
	{%?($SOURCE/@CONVENIO       ='') {% %} {% and ORG18_CATEGORIAS.oi_convenio = { $SOURCE/@CONVENIO } %} %}
	{%?($SOURCE/@POSICION       ='') {% %} {% and L.oi_posicion_ult = { $SOURCE/@POSICION } %} %}
	{%?($SOURCE/@PUESTO         ='') {% %} {% and ORG04_POSICIONES.oi_puesto = { $SOURCE/@PUESTO } %} %}
	{%?($SOURCE/@LOCALIDAD_NAC  ='') {% %} {% and P.oi_local_nacim = { $SOURCE/@LOCALIDAD_NAC } %} %}
	{%?($SOURCE/@PROVINCIA_NAC  ='') {% %} {% and LOC_NAC.oi_provincia = { $SOURCE/@PROVINCIA_NAC } %} %}
	{%?($SOURCE/@PAIS_NAC       ='') {% %} {% and LOC_NAC.oi_pais = { $SOURCE/@PAIS_NAC } %} %}
	{%?($SOURCE/@LOCALIDAD_RES  ='') {% %} {% and LOC_RES.oi_localidad = { $SOURCE/@LOCALIDAD_RES } %} %}
	{%?($SOURCE/@PROVINCIA_RES  ='') {% %} {% and LOC_RES.oi_provincia = { $SOURCE/@PROVINCIA_RES } %} %}
	{%?($SOURCE/@PAIS_RES       ='') {% %} {% and LOC_RES.oi_pais = { $SOURCE/@PAIS_RES } %} %}
')/ROWS
